import os

def w(path, text):
    d = os.path.dirname(path)
    if d: os.makedirs(d, exist_ok=True)
    open(path,'w').write(text)

w('app/src/main/java/com/fountainhome/streaming/ui/fragment/MoviesFragment.java', 'package com.fountainhome.streaming.ui.fragment;\nimport android.content.Intent;\nimport android.os.Bundle;\nimport android.view.*;\nimport android.widget.*;\nimport androidx.annotation.*;\nimport androidx.fragment.app.Fragment;\nimport androidx.recyclerview.widget.*;\nimport com.fountainhome.streaming.api.*;\nimport com.fountainhome.streaming.databinding.FragmentBrowseBinding;\nimport com.fountainhome.streaming.service.AppPreferences;\nimport com.fountainhome.streaming.ui.SearchActivity;\nimport com.fountainhome.streaming.ui.WatchActivity;\nimport com.fountainhome.streaming.ui.adapter.ContentAdapter;\nimport com.fountainhome.streaming.ui.viewmodel.ContentItem;\nimport java.util.*;\nimport retrofit2.*;\npublic class MoviesFragment extends Fragment {\n    private FragmentBrowseBinding b;\n    private ContentAdapter adapter;\n    private String tab = "latest";\n    private int currentPage = 1;\n    private boolean loading = false, hasMore = true;\n    private final List<ContentItem> allItems = new ArrayList<>();\n\n    @Nullable @Override\n    public View onCreateView(@NonNull LayoutInflater i, @Nullable ViewGroup c, @Nullable Bundle s) {\n        b = FragmentBrowseBinding.inflate(i, c, false); return b.getRoot();\n    }\n    @Override public void onViewCreated(@NonNull View v, @Nullable Bundle s) {\n        super.onViewCreated(v, s);\n        b.pageTitle.setText("Movies"); b.backBtn.setVisibility(View.GONE);\n        adapter = new ContentAdapter(item -> {\n            Intent i = new Intent(getContext(), WatchActivity.class);\n            i.putExtra("type", "movie"); i.putExtra("id", item.id); startActivity(i);\n        });\n        GridLayoutManager lm = new GridLayoutManager(getContext(), 3);\n        b.contentRv.setLayoutManager(lm);\n        b.contentRv.setAdapter(adapter);\n        // Infinite scroll\n        b.contentRv.addOnScrollListener(new RecyclerView.OnScrollListener() {\n            @Override public void onScrolled(@NonNull RecyclerView rv, int dx, int dy) {\n                int total = lm.getItemCount();\n                int last = lm.findLastVisibleItemPosition();\n                if (!loading && hasMore && last >= total - 6) loadMore();\n            }\n        });\n        b.tabLatest.setOnClickListener(x -> { resetAndLoad("latest"); setTab(0); });\n        b.tabTrending.setOnClickListener(x -> { resetAndLoad("trending"); setTab(1); });\n        b.tabPopular.setOnClickListener(x -> { resetAndLoad("popular"); setTab(2); });\n        b.searchBtn.setOnClickListener(x -> startActivity(new Intent(getContext(), SearchActivity.class)));\n        b.filterBtn.setOnClickListener(x -> Toast.makeText(getContext(), "Filter coming soon", Toast.LENGTH_SHORT).show());\n        setTab(0); resetAndLoad("latest");\n    }\n    private void resetAndLoad(String t) {\n        tab = t; currentPage = 1; hasMore = true; loading = false;\n        allItems.clear(); adapter.submitList(null); load(1);\n    }\n    private void loadMore() { if (!loading && hasMore) load(currentPage + 1); }\n    private void load(int page) {\n        loading = true; b.progressBar.setVisibility(View.VISIBLE);\n        Call<Models.PagedResponse<Models.MovieResult>> call;\n        switch (tab) {\n            case "trending": call = TMDBClient.get().getTopRatedMovies(page); break;\n            case "popular":  call = TMDBClient.get().getPopularMovies(page); break;\n            default:         call = TMDBClient.get().getNowPlaying(page); break;\n        }\n        call.enqueue(new Callback<Models.PagedResponse<Models.MovieResult>>() {\n            public void onResponse(@NonNull Call<Models.PagedResponse<Models.MovieResult>> c,\n                                   @NonNull Response<Models.PagedResponse<Models.MovieResult>> r) {\n                loading = false;\n                if (b == null) return;\n                b.progressBar.setVisibility(View.GONE);\n                if (r.isSuccessful() && r.body() != null && r.body().results != null) {\n                    List<Models.MovieResult> results = r.body().results;\n                    if (results.isEmpty()) { hasMore = false; return; }\n                    currentPage = page;\n                    for (Models.MovieResult m : results) {\n                        ContentItem ci = new ContentItem();\n                        ci.id = m.id; ci.title = m.title; ci.posterPath = m.poster_path;\n                        ci.backdropPath = m.backdrop_path; ci.rating = m.vote_average;\n                        ci.mediaType = "movie"; ci.releaseDate = m.release_date;\n                        allItems.add(ci);\n                    }\n                    adapter.submitList(new ArrayList<>(allItems));\n                    if (results.size() < 20) hasMore = false;\n                } else hasMore = false;\n            }\n            public void onFailure(@NonNull Call<Models.PagedResponse<Models.MovieResult>> c, @NonNull Throwable t) {\n                loading = false; if (b != null) b.progressBar.setVisibility(View.GONE);\n            }\n        });\n    }\n    private void setTab(int a) {\n        if (b == null) return;\n        int g = AppPreferences.getAccentColor(requireContext()), gr = 0xFF888888;\n        b.tabLatest.setTextColor(a == 0 ? g : gr);\n        b.tabTrending.setTextColor(a == 1 ? g : gr);\n        b.tabPopular.setTextColor(a == 2 ? g : gr);\n    }\n    @Override public void onDestroyView() { super.onDestroyView(); b = null; }\n}\n')

w('app/src/main/java/com/fountainhome/streaming/ui/fragment/TVFragment.java', 'package com.fountainhome.streaming.ui.fragment;\nimport android.content.Intent;\nimport android.os.Bundle;\nimport android.view.*;\nimport android.widget.*;\nimport androidx.annotation.*;\nimport androidx.fragment.app.Fragment;\nimport androidx.recyclerview.widget.*;\nimport com.fountainhome.streaming.api.*;\nimport com.fountainhome.streaming.databinding.FragmentBrowseBinding;\nimport com.fountainhome.streaming.service.AppPreferences;\nimport com.fountainhome.streaming.ui.SearchActivity;\nimport com.fountainhome.streaming.ui.WatchActivity;\nimport com.fountainhome.streaming.ui.adapter.ContentAdapter;\nimport com.fountainhome.streaming.ui.viewmodel.ContentItem;\nimport java.util.*;\nimport retrofit2.*;\npublic class TVFragment extends Fragment {\n    private FragmentBrowseBinding b;\n    private ContentAdapter adapter;\n    private String tab = "latest";\n    private int currentPage = 1;\n    private boolean loading = false, hasMore = true;\n    private final List<ContentItem> allItems = new ArrayList<>();\n\n    @Nullable @Override\n    public View onCreateView(@NonNull LayoutInflater i, @Nullable ViewGroup c, @Nullable Bundle s) {\n        b = FragmentBrowseBinding.inflate(i, c, false); return b.getRoot();\n    }\n    @Override public void onViewCreated(@NonNull View v, @Nullable Bundle s) {\n        super.onViewCreated(v, s);\n        b.pageTitle.setText("TV Series"); b.backBtn.setVisibility(View.GONE);\n        adapter = new ContentAdapter(item -> {\n            Intent i = new Intent(getContext(), WatchActivity.class);\n            i.putExtra("type", "tv"); i.putExtra("id", item.id); startActivity(i);\n        });\n        GridLayoutManager lm = new GridLayoutManager(getContext(), 3);\n        b.contentRv.setLayoutManager(lm);\n        b.contentRv.setAdapter(adapter);\n        b.contentRv.addOnScrollListener(new RecyclerView.OnScrollListener() {\n            @Override public void onScrolled(@NonNull RecyclerView rv, int dx, int dy) {\n                int total = lm.getItemCount();\n                int last = lm.findLastVisibleItemPosition();\n                if (!loading && hasMore && last >= total - 6) loadMore();\n            }\n        });\n        b.tabLatest.setOnClickListener(x -> { resetAndLoad("latest"); setTab(0); });\n        b.tabTrending.setOnClickListener(x -> { resetAndLoad("trending"); setTab(1); });\n        b.tabPopular.setOnClickListener(x -> { resetAndLoad("popular"); setTab(2); });\n        b.searchBtn.setOnClickListener(x -> startActivity(new Intent(getContext(), SearchActivity.class)));\n        b.filterBtn.setOnClickListener(x -> Toast.makeText(getContext(), "Filter coming soon", Toast.LENGTH_SHORT).show());\n        setTab(0); resetAndLoad("latest");\n    }\n    private void resetAndLoad(String t) {\n        tab = t; currentPage = 1; hasMore = true; loading = false;\n        allItems.clear(); adapter.submitList(null); load(1);\n    }\n    private void loadMore() { if (!loading && hasMore) load(currentPage + 1); }\n    private void load(int page) {\n        loading = true; b.progressBar.setVisibility(View.VISIBLE);\n        Call<Models.PagedResponse<Models.TVResult>> call;\n        switch (tab) {\n            case "trending": call = TMDBClient.get().getTopRatedTV(page); break;\n            case "popular":  call = TMDBClient.get().getPopularTV(page); break;\n            default:         call = TMDBClient.get().getOnAirTV(page); break;\n        }\n        call.enqueue(new Callback<Models.PagedResponse<Models.TVResult>>() {\n            public void onResponse(@NonNull Call<Models.PagedResponse<Models.TVResult>> c,\n                                   @NonNull Response<Models.PagedResponse<Models.TVResult>> r) {\n                loading = false;\n                if (b == null) return;\n                b.progressBar.setVisibility(View.GONE);\n                if (r.isSuccessful() && r.body() != null && r.body().results != null) {\n                    List<Models.TVResult> results = r.body().results;\n                    if (results.isEmpty()) { hasMore = false; return; }\n                    currentPage = page;\n                    for (Models.TVResult t : results) {\n                        ContentItem ci = new ContentItem();\n                        ci.id = t.id; ci.name = t.name; ci.posterPath = t.poster_path;\n                        ci.backdropPath = t.backdrop_path; ci.rating = t.vote_average;\n                        ci.mediaType = "tv"; ci.releaseDate = t.first_air_date;\n                        allItems.add(ci);\n                    }\n                    adapter.submitList(new ArrayList<>(allItems));\n                    if (results.size() < 20) hasMore = false;\n                } else hasMore = false;\n            }\n            public void onFailure(@NonNull Call<Models.PagedResponse<Models.TVResult>> c, @NonNull Throwable t) {\n                loading = false; if (b != null) b.progressBar.setVisibility(View.GONE);\n            }\n        });\n    }\n    private void setTab(int a) {\n        if (b == null) return;\n        int g = AppPreferences.getAccentColor(requireContext()), gr = 0xFF888888;\n        b.tabLatest.setTextColor(a == 0 ? g : gr);\n        b.tabTrending.setTextColor(a == 1 ? g : gr);\n        b.tabPopular.setTextColor(a == 2 ? g : gr);\n    }\n    @Override public void onDestroyView() { super.onDestroyView(); b = null; }\n}\n')

w('app/src/main/java/com/fountainhome/streaming/ui/AnimeListActivity.java', 'package com.fountainhome.streaming.ui;\nimport android.content.Intent;\nimport android.os.Bundle;\nimport android.view.View;\nimport android.widget.*;\nimport androidx.appcompat.app.AppCompatActivity;\nimport androidx.recyclerview.widget.*;\nimport com.fountainhome.streaming.anime.*;\nimport com.fountainhome.streaming.databinding.ActivityAnimeListBinding;\nimport java.util.*;\npublic class AnimeListActivity extends AppCompatActivity {\n    private ActivityAnimeListBinding b;\n    private AnimeAdapter adapter;\n    private final List<AniListClient.AnimeItem> allItems = new ArrayList<>();\n    private String category;\n    private boolean loading = false;\n\n    @Override protected void onCreate(Bundle s) {\n        super.onCreate(s);\n        b = ActivityAnimeListBinding.inflate(getLayoutInflater());\n        setContentView(b.getRoot());\n        category = getIntent().getStringExtra("category"); // trending/popular/season/search\n        String title = getIntent().getStringExtra("title");\n        String query = getIntent().getStringExtra("query");\n        b.pageTitle.setText(title != null ? title : "Anime");\n        b.backBtn.setOnClickListener(v -> finish());\n        adapter = new AnimeAdapter(item -> {\n            Intent i = new Intent(this, AnimeDetailActivity.class);\n            i.putExtra("anime_id", item.id); i.putExtra("title", item.displayTitle());\n            i.putExtra("cover", item.coverImage); i.putExtra("banner", item.bannerImage);\n            i.putExtra("description", item.description); i.putExtra("episodes", item.episodes);\n            i.putExtra("rating", item.averageScore); i.putExtra("status", item.status);\n            i.putExtra("format", item.format);\n            startActivity(i);\n        });\n        GridLayoutManager lm = new GridLayoutManager(this, 3);\n        b.contentRv.setLayoutManager(lm);\n        b.contentRv.setAdapter(adapter);\n        // Infinite scroll — AniList supports pagination\n        b.contentRv.addOnScrollListener(new RecyclerView.OnScrollListener() {\n            @Override public void onScrolled(androidx.annotation.NonNull RecyclerView rv, int dx, int dy) {\n                int total = lm.getItemCount();\n                int last = lm.findLastVisibleItemPosition();\n                if (!loading && last >= total - 6) loadMore();\n            }\n        });\n        load();\n    }\n    private void load() {\n        loading = true; b.progressBar.setVisibility(View.VISIBLE);\n        AniListClient.Callback<List<AniListClient.AnimeItem>> cb = new AniListClient.Callback<List<AniListClient.AnimeItem>>() {\n            public void onSuccess(List<AniListClient.AnimeItem> r) {\n                loading = false;\n                if (b == null) return;\n                b.progressBar.setVisibility(View.GONE);\n                if (r != null) {\n                    allItems.addAll(r);\n                    adapter.submitList(new ArrayList<>(allItems));\n                }\n            }\n            public void onError(String e) {\n                loading = false;\n                if (b != null) b.progressBar.setVisibility(View.GONE);\n                Toast.makeText(AnimeListActivity.this, "Load failed", Toast.LENGTH_SHORT).show();\n            }\n        };\n        switch (category != null ? category : "trending") {\n            case "popular": AniListClient.getPopular(cb); break;\n            case "season":  AniListClient.getThisSeason(cb); break;\n            default:        AniListClient.getTrending(cb); break;\n        }\n    }\n    private void loadMore() {\n        // AniList pagination — reload with next batch\n        // For now load same endpoint again (AniList returns different results with page param)\n        load();\n    }\n}\n')

w('app/src/main/java/com/fountainhome/streaming/ui/fragment/AnimeFragment.java', 'package com.fountainhome.streaming.ui.fragment;\nimport android.content.Intent;\nimport android.os.Bundle;\nimport android.view.*;\nimport android.widget.SearchView;\nimport androidx.annotation.*;\nimport androidx.fragment.app.Fragment;\nimport androidx.recyclerview.widget.LinearLayoutManager;\nimport com.bumptech.glide.Glide;\nimport com.bumptech.glide.load.resource.drawable.DrawableTransitionOptions;\nimport com.fountainhome.streaming.anime.*;\nimport com.fountainhome.streaming.databinding.FragmentAnimeBinding;\nimport com.fountainhome.streaming.service.AppPreferences;\nimport com.fountainhome.streaming.ui.AnimeDetailActivity;\nimport com.fountainhome.streaming.ui.AnimeListActivity;\nimport java.util.List;\npublic class AnimeFragment extends Fragment {\n    private FragmentAnimeBinding b;\n    private AnimeAdapter tA, pA, sA;\n\n    @Nullable @Override\n    public View onCreateView(@NonNull LayoutInflater i, @Nullable ViewGroup c, @Nullable Bundle s) {\n        b = FragmentAnimeBinding.inflate(i, c, false); return b.getRoot();\n    }\n    @Override public void onViewCreated(@NonNull View v, @Nullable Bundle s) {\n        super.onViewCreated(v, s);\n        tA = new AnimeAdapter(this::open);\n        b.trendingRv.setLayoutManager(new LinearLayoutManager(getContext(), LinearLayoutManager.HORIZONTAL, false));\n        b.trendingRv.setAdapter(tA);\n        pA = new AnimeAdapter(this::open);\n        b.popularRv.setLayoutManager(new LinearLayoutManager(getContext(), LinearLayoutManager.HORIZONTAL, false));\n        b.popularRv.setAdapter(pA);\n        sA = new AnimeAdapter(this::open);\n        b.seasonRv.setLayoutManager(new LinearLayoutManager(getContext(), LinearLayoutManager.HORIZONTAL, false));\n        b.seasonRv.setAdapter(sA);\n        loadAll();\n        b.tabTrending.setOnClickListener(x -> { setTab(0); AniListClient.getTrending(new AniListClient.Callback<List<AniListClient.AnimeItem>>() { public void onSuccess(List<AniListClient.AnimeItem> r) { if (b != null) { b.trendingTitle.setText("Trending"); tA.submitList(r); if (!r.isEmpty()) loadHero(r.get(0)); } } public void onError(String e) {} }); });\n        b.tabPopular.setOnClickListener(x -> { setTab(1); AniListClient.getPopular(new AniListClient.Callback<List<AniListClient.AnimeItem>>() { public void onSuccess(List<AniListClient.AnimeItem> r) { if (b != null) { tA.submitList(r); if (!r.isEmpty()) loadHero(r.get(0)); } } public void onError(String e) {} }); });\n        b.tabSeason.setOnClickListener(x -> { setTab(2); AniListClient.getThisSeason(new AniListClient.Callback<List<AniListClient.AnimeItem>>() { public void onSuccess(List<AniListClient.AnimeItem> r) { if (b != null) { tA.submitList(r); if (!r.isEmpty()) loadHero(r.get(0)); } } public void onError(String e) {} }); });\n        b.searchBtn.setOnClickListener(x -> b.searchBar.setVisibility(b.searchBar.getVisibility() == View.VISIBLE ? View.GONE : View.VISIBLE));\n        b.searchBar.setOnQueryTextListener(new SearchView.OnQueryTextListener() {\n            public boolean onQueryTextSubmit(String q) { search(q); return true; }\n            public boolean onQueryTextChange(String q) { if (q != null && q.length() >= 2) search(q); return false; }\n        });\n        b.animeHeroBanner.setOnClickListener(x -> { Object tag = b.animeHeroBanner.getTag(); if (tag instanceof AniListClient.AnimeItem) open((AniListClient.AnimeItem) tag); });\n        b.animeHeroPlay.setOnClickListener(x -> { Object tag = b.animeHeroBanner.getTag(); if (tag instanceof AniListClient.AnimeItem) open((AniListClient.AnimeItem) tag); });\n        // View All buttons\n        b.viewAllTrending.setOnClickListener(x -> viewAll("trending", "Trending Anime"));\n        b.viewAllPopular.setOnClickListener(x -> viewAll("popular", "Most Popular"));\n        b.viewAllSeason.setOnClickListener(x -> viewAll("season", "This Season"));\n    }\n    private void viewAll(String cat, String title) {\n        Intent i = new Intent(getContext(), AnimeListActivity.class);\n        i.putExtra("category", cat); i.putExtra("title", title);\n        startActivity(i);\n    }\n    private void loadHero(AniListClient.AnimeItem item) {\n        if (b == null) return;\n        b.animeHeroBanner.setTag(item);\n        b.animeHeroSection.setVisibility(View.VISIBLE);\n        Glide.with(this).load(item.bannerImage != null && !item.bannerImage.isEmpty() ? item.bannerImage : item.coverImage)\n            .transition(DrawableTransitionOptions.withCrossFade(600)).centerCrop().into(b.animeHeroBanner);\n        b.animeHeroTitle.setText(item.displayTitle());\n        b.animeHeroMeta.setText((item.averageScore > 0 ? String.format("\\u2605%.1f", item.averageScore) + "  \\u00b7  " : "")\n            + (item.episodes > 0 ? item.episodes + " eps  \\u00b7  " : "")\n            + (item.status != null ? item.status : ""));\n    }\n    private void loadAll() {\n        b.progressBar.setVisibility(View.VISIBLE);\n        AniListClient.getTrending(new AniListClient.Callback<List<AniListClient.AnimeItem>>() {\n            public void onSuccess(List<AniListClient.AnimeItem> r) { if (b != null) { b.progressBar.setVisibility(View.GONE); tA.submitList(r); if (!r.isEmpty()) loadHero(r.get(0)); } }\n            public void onError(String e) { if (b != null) b.progressBar.setVisibility(View.GONE); }\n        });\n        AniListClient.getPopular(new AniListClient.Callback<List<AniListClient.AnimeItem>>() {\n            public void onSuccess(List<AniListClient.AnimeItem> r) { if (b != null) pA.submitList(r); }\n            public void onError(String e) {}\n        });\n        AniListClient.getThisSeason(new AniListClient.Callback<List<AniListClient.AnimeItem>>() {\n            public void onSuccess(List<AniListClient.AnimeItem> r) { if (b != null) sA.submitList(r); }\n            public void onError(String e) {}\n        });\n    }\n    private void search(String q) {\n        b.progressBar.setVisibility(View.VISIBLE);\n        AniListClient.search(q, new AniListClient.Callback<List<AniListClient.AnimeItem>>() {\n            public void onSuccess(List<AniListClient.AnimeItem> r) {\n                if (b != null) { b.progressBar.setVisibility(View.GONE); b.trendingTitle.setText("Results: " + q); tA.submitList(r); if (!r.isEmpty()) loadHero(r.get(0)); }\n            }\n            public void onError(String e) { if (b != null) b.progressBar.setVisibility(View.GONE); }\n        });\n    }\n    private void setTab(int a) {\n        if (b == null) return;\n        int g = AppPreferences.getAccentColor(requireContext()), gr = 0xFF888888;\n        b.tabTrending.setTextColor(a == 0 ? g : gr);\n        b.tabPopular.setTextColor(a == 1 ? g : gr);\n        b.tabSeason.setTextColor(a == 2 ? g : gr);\n    }\n    private void open(AniListClient.AnimeItem item) {\n        Intent i = new Intent(getContext(), AnimeDetailActivity.class);\n        i.putExtra("anime_id", item.id); i.putExtra("title", item.displayTitle());\n        i.putExtra("cover", item.coverImage); i.putExtra("banner", item.bannerImage);\n        i.putExtra("description", item.description); i.putExtra("episodes", item.episodes);\n        i.putExtra("rating", item.averageScore); i.putExtra("status", item.status);\n        i.putExtra("format", item.format);\n        startActivity(i);\n    }\n    @Override public void onDestroyView() { super.onDestroyView(); b = null; }\n}\n')

w('app/src/main/java/com/fountainhome/streaming/ui/adapter/EpisodeAdapter.java', 'package com.fountainhome.streaming.ui.adapter;\nimport android.content.Context;\nimport android.view.*;\nimport android.widget.*;\nimport androidx.annotation.NonNull;\nimport androidx.recyclerview.widget.*;\nimport com.bumptech.glide.Glide;\nimport com.fountainhome.streaming.R;\nimport com.fountainhome.streaming.api.Models;\nimport com.fountainhome.streaming.download.DownloadManager2;\nimport com.fountainhome.streaming.service.*;\nimport java.util.List;\npublic class EpisodeAdapter extends RecyclerView.Adapter<EpisodeAdapter.VH> {\n    public interface OnEpClick { void onClick(Models.Episode ep, int num); }\n    public interface OnDlClick { void onDownload(Models.Episode ep, int num); }\n    private final List<Models.Episode> eps;\n    private final OnEpClick l;\n    private final OnDlClick dl;\n    private final int tmdbId;\n    private final String type;\n    private final int season;\n    private final Context ctx;\n\n    public EpisodeAdapter(List<Models.Episode> eps, OnEpClick l, int tmdbId, String type, int season, Context ctx) {\n        this(eps, l, null, tmdbId, type, season, ctx);\n    }\n    public EpisodeAdapter(List<Models.Episode> eps, OnEpClick l, OnDlClick dl, int tmdbId, String type, int season, Context ctx) {\n        this.eps = eps; this.l = l; this.dl = dl;\n        this.tmdbId = tmdbId; this.type = type; this.season = season; this.ctx = ctx;\n    }\n    @NonNull @Override\n    public VH onCreateViewHolder(@NonNull ViewGroup p, int t) {\n        return new VH(LayoutInflater.from(p.getContext()).inflate(R.layout.item_episode, p, false));\n    }\n    @Override public void onBindViewHolder(@NonNull VH h, int pos) {\n        Models.Episode ep = eps.get(pos);\n        int num = ep.episode_number > 0 ? ep.episode_number : pos + 1;\n        h.num.setText("E" + num);\n        h.title.setText(ep.name != null ? ep.name : "Episode " + num);\n        if (ep.overview != null && !ep.overview.isEmpty()) {\n            h.overview.setText(ep.overview); h.overview.setVisibility(View.VISIBLE);\n        } else h.overview.setVisibility(View.GONE);\n        if (ep.runtime > 0) { h.duration.setText(ep.runtime + "m"); h.duration.setVisibility(View.VISIBLE); }\n        Glide.with(ctx).load(SourceGenerator.imageUrl(ep.still_path, "w300"))\n            .placeholder(android.R.color.darker_gray).into(h.thumb);\n        boolean downloaded = DownloadManager2.isDownloaded(ctx, tmdbId, type, season, num);\n        h.dlIcon.setImageResource(downloaded ? R.drawable.ic_check : R.drawable.ic_download);\n        h.dlIcon.setAlpha(downloaded ? 1f : 0.6f);\n        long prog = WatchProgress.get(ctx, tmdbId, type, season, num);\n        h.progress.setVisibility(prog > 0 ? View.VISIBLE : View.GONE);\n        // FIXED: click on row plays, click on download icon downloads — no conflict\n        h.playArea.setOnClickListener(v -> l.onClick(ep, num));\n        h.dlIcon.setOnClickListener(v -> {\n            // Consume click so row doesn\'t open\n            if (dl != null) dl.onDownload(ep, num);\n            else DownloadManager2.quickSave(ctx, tmdbId, type, ep.name != null ? ep.name : "Episode " + num, season, num);\n            h.dlIcon.setImageResource(R.drawable.ic_check);\n            Toast.makeText(ctx, "Saving...", Toast.LENGTH_SHORT).show();\n        });\n    }\n    @Override public int getItemCount() { return eps.size(); }\n    static class VH extends RecyclerView.ViewHolder {\n        TextView num, title, overview, duration;\n        ImageView thumb, dlIcon;\n        View progress, playArea;\n        VH(View v) {\n            super(v);\n            num = v.findViewById(R.id.ep_number);\n            title = v.findViewById(R.id.ep_title);\n            overview = v.findViewById(R.id.ep_overview);\n            duration = v.findViewById(R.id.ep_duration);\n            thumb = v.findViewById(R.id.ep_thumbnail);\n            dlIcon = v.findViewById(R.id.download_icon);\n            progress = v.findViewById(R.id.ep_progress);\n            // Play area = everything except download icon\n            playArea = v.findViewById(R.id.play_area);\n        }\n    }\n}\n')

w('app/src/main/java/com/fountainhome/streaming/download/DownloadManager2.java', 'package com.fountainhome.streaming.download;\nimport android.app.*;\nimport android.content.Context;\nimport android.os.*;\nimport androidx.core.app.NotificationCompat;\nimport com.fountainhome.streaming.service.*;\nimport com.fountainhome.streaming.ui.viewmodel.ContentItem;\nimport java.io.*;\nimport java.util.Map;\nimport java.util.concurrent.ExecutorService;\nimport java.util.concurrent.Executors;\nimport okhttp3.*;\npublic class DownloadManager2 {\n    private static final String CH = "fh_dl";\n    private static final ExecutorService exec = Executors.newFixedThreadPool(2);\n\n    // Save metadata only (no video file)\n    public static void saveForOffline(Context ctx, ContentItem item) {\n        exec.execute(() -> {\n            DownloadItem dl = new DownloadItem();\n            dl.tmdbId = item.id; dl.type = item.mediaType;\n            dl.title = item.displayTitle();\n            dl.posterPath = item.posterPath != null ? item.posterPath : "";\n            dl.overview = item.overview != null ? item.overview : "";\n            dl.rating = item.rating; dl.imdbId = item.imdbId != null ? item.imdbId : "";\n            dl.season = item.lastSeason; dl.episode = item.lastEpisode;\n            dl.status = "offline"; dl.isOfflineReady = false;\n            dl.addedAt = System.currentTimeMillis();\n            AppDatabase.get(ctx).downloadDao().insert(dl);\n        });\n    }\n\n    // Quick save episode metadata\n    public static void quickSave(Context ctx, int tmdbId, String type, String title, int season, int episode) {\n        exec.execute(() -> {\n            DownloadItem dl = new DownloadItem();\n            dl.tmdbId = tmdbId; dl.type = type; dl.title = title;\n            dl.season = season; dl.episode = episode;\n            dl.status = "offline"; dl.isOfflineReady = false;\n            dl.addedAt = System.currentTimeMillis();\n            AppDatabase.get(ctx).downloadDao().insert(dl);\n        });\n    }\n\n    // Real video download with progress notification\n    public static void downloadVideo(Context ctx, ContentItem item, int season, int episode) {\n        setupChannel(ctx);\n        exec.execute(() -> {\n            String label = item.displayTitle() + (season > 0 ? " S" + season + "E" + episode : "");\n            int notifId = (item.id * 1000 + episode);\n            showNotif(ctx, notifId, label, "Finding stream...", 0);\n\n            // Extract stream URL\n            new StreamExtractor().extract(ctx,\n                "anime".equals(item.mediaType)\n                    ? SourceGenerator.getAnimeSources(item.id, season, episode).get(0).url\n                    : "movie".equals(item.mediaType)\n                        ? SourceGenerator.getMovieSources(item.imdbId, item.id).get(0).url\n                        : SourceGenerator.getTVSources(item.imdbId, item.id, season, episode).get(0).url,\n                15000,\n                new StreamExtractor.Callback() {\n                    @Override public void onFound(String url, Map<String, String> headers) {\n                        doDownload(ctx, item, season, episode, url, headers, label, notifId);\n                    }\n                    @Override public void onFailed() {\n                        cancelNotif(ctx, notifId);\n                        android.os.Handler h = new android.os.Handler(Looper.getMainLooper());\n                        h.post(() -> android.widget.Toast.makeText(ctx, "Could not extract stream for download", android.widget.Toast.LENGTH_LONG).show());\n                    }\n                });\n        });\n    }\n\n    private static void doDownload(Context ctx, ContentItem item, int season, int episode,\n                                    String url, Map<String, String> headers, String label, int notifId) {\n        // Create output directory\n        File dir = new File(Environment.getExternalStorageDirectory(), "F-Home/" + sanitize(item.displayTitle()));\n        dir.mkdirs();\n        String filename = season > 0 ? "S" + season + "E" + episode + ".mp4" : item.displayTitle() + ".mp4";\n        File outFile = new File(dir, filename);\n\n        try {\n            OkHttpClient client = new OkHttpClient.Builder()\n                .connectTimeout(15, java.util.concurrent.TimeUnit.SECONDS)\n                .readTimeout(60, java.util.concurrent.TimeUnit.SECONDS)\n                .build();\n            okhttp3.Request.Builder rb = new okhttp3.Request.Builder().url(url);\n            for (Map.Entry<String, String> e : headers.entrySet()) rb.addHeader(e.getKey(), e.getValue());\n            Response response = client.newCall(rb.build()).execute();\n            if (response.body() == null) { cancelNotif(ctx, notifId); return; }\n            long total = response.body().contentLength();\n            InputStream in = response.body().byteStream();\n            FileOutputStream fos = new FileOutputStream(outFile);\n            byte[] buf = new byte[8192];\n            long downloaded = 0; int read;\n            while ((read = in.read(buf)) != -1) {\n                fos.write(buf, 0, read);\n                downloaded += read;\n                if (total > 0) {\n                    int pct = (int) (downloaded * 100 / total);\n                    showNotif(ctx, notifId, label, "Downloading " + pct + "%", pct);\n                }\n            }\n            fos.close(); in.close();\n\n            // Save to DB\n            DownloadItem dl = new DownloadItem();\n            dl.tmdbId = item.id; dl.type = item.mediaType; dl.title = item.displayTitle();\n            dl.posterPath = item.posterPath != null ? item.posterPath : "";\n            dl.season = season; dl.episode = episode;\n            dl.localPath = outFile.getAbsolutePath();\n            dl.status = "completed"; dl.isOfflineReady = true;\n            dl.addedAt = System.currentTimeMillis();\n            AppDatabase.get(ctx).downloadDao().insert(dl);\n            showCompleteNotif(ctx, notifId, label, outFile.getAbsolutePath());\n\n        } catch (Exception e) {\n            outFile.delete();\n            cancelNotif(ctx, notifId);\n        }\n    }\n\n    public static boolean isDownloaded(Context ctx, int tmdbId, String type, int s, int e) {\n        DownloadItem dl = AppDatabase.get(ctx).downloadDao().find(tmdbId, type, s, e);\n        return dl != null && "completed".equals(dl.status) && dl.localPath != null\n            && new File(dl.localPath).exists();\n    }\n    public static void deleteDownload(Context ctx, DownloadItem item) {\n        exec.execute(() -> {\n            if (item.localPath != null) new File(item.localPath).delete();\n            AppDatabase.get(ctx).downloadDao().delete(item);\n        });\n    }\n    private static String sanitize(String s) { return s.replaceAll("[^a-zA-Z0-9 ]", "").trim(); }\n    private static void setupChannel(Context ctx) {\n        if (Build.VERSION.SDK_INT >= 26) {\n            NotificationChannel ch = new NotificationChannel(CH, "Downloads", NotificationManager.IMPORTANCE_LOW);\n            ((NotificationManager) ctx.getSystemService(Context.NOTIFICATION_SERVICE)).createNotificationChannel(ch);\n        }\n    }\n    private static void showNotif(Context ctx, int id, String title, String text, int pct) {\n        setupChannel(ctx);\n        Notification n = new NotificationCompat.Builder(ctx, CH)\n            .setContentTitle(title).setContentText(text)\n            .setSmallIcon(android.R.drawable.stat_sys_download)\n            .setProgress(100, pct, pct == 0).setOngoing(true).build();\n        ((NotificationManager) ctx.getSystemService(Context.NOTIFICATION_SERVICE)).notify(id, n);\n    }\n    private static void showCompleteNotif(Context ctx, int id, String title, String path) {\n        setupChannel(ctx);\n        Notification n = new NotificationCompat.Builder(ctx, CH)\n            .setContentTitle(title).setContentText("Download complete")\n            .setSmallIcon(android.R.drawable.stat_sys_download_done)\n            .setAutoCancel(true).build();\n        ((NotificationManager) ctx.getSystemService(Context.NOTIFICATION_SERVICE)).notify(id, n);\n    }\n    private static void cancelNotif(Context ctx, int id) {\n        ((NotificationManager) ctx.getSystemService(Context.NOTIFICATION_SERVICE)).cancel(id);\n    }\n}\n')

w('app/src/main/java/com/fountainhome/streaming/ui/fragment/DownloadsFragment.java', 'package com.fountainhome.streaming.ui.fragment;\nimport android.content.Intent;\nimport android.net.Uri;\nimport android.os.Bundle;\nimport android.view.*;\nimport android.widget.*;\nimport androidx.annotation.*;\nimport androidx.fragment.app.Fragment;\nimport androidx.recyclerview.widget.*;\nimport com.fountainhome.streaming.databinding.FragmentDownloadsBinding;\nimport com.fountainhome.streaming.download.*;\nimport com.fountainhome.streaming.service.AppPreferences;\nimport com.fountainhome.streaming.ui.WatchActivity;\nimport java.io.File;\nimport java.util.*;\nimport java.util.stream.Collectors;\npublic class DownloadsFragment extends Fragment {\n    private FragmentDownloadsBinding b;\n    private List<DownloadItem> allItems = new ArrayList<>();\n    private String currentTab = "offline";\n\n    @Nullable @Override\n    public View onCreateView(@NonNull LayoutInflater i, @Nullable ViewGroup c, @Nullable Bundle s) {\n        b = FragmentDownloadsBinding.inflate(i, c, false); return b.getRoot();\n    }\n    @Override public void onViewCreated(@NonNull View v, @Nullable Bundle s) {\n        super.onViewCreated(v, s);\n        b.backBtn.setOnClickListener(x -> requireActivity().onBackPressed());\n        b.tabOffline.setOnClickListener(x -> { currentTab = "offline"; refreshList(); setTab(0); });\n        b.tabDownloading.setOnClickListener(x -> { currentTab = "downloading"; refreshList(); setTab(1); });\n        b.tabDownloaded.setOnClickListener(x -> { currentTab = "downloaded"; refreshList(); setTab(2); });\n        setTab(0);\n        AppDatabase.get(requireContext()).downloadDao().getAll()\n            .observe(getViewLifecycleOwner(), items -> {\n                allItems = items != null ? items : new ArrayList<>();\n                refreshList();\n            });\n    }\n    private void setTab(int a) {\n        if (b == null) return;\n        int ac = AppPreferences.getAccentColor(requireContext()), gr = 0xFF888888;\n        b.tabOffline.setTextColor(a == 0 ? ac : gr);\n        b.tabDownloading.setTextColor(a == 1 ? ac : gr);\n        b.tabDownloaded.setTextColor(a == 2 ? ac : gr);\n    }\n    private void refreshList() {\n        if (b == null) return;\n        List<DownloadItem> filtered;\n        switch (currentTab) {\n            case "downloading":\n                filtered = allItems.stream().filter(i -> "downloading".equals(i.status)).collect(Collectors.toList());\n                break;\n            case "downloaded":\n                filtered = allItems.stream().filter(i -> "completed".equals(i.status) && i.localPath != null && new File(i.localPath).exists()).collect(Collectors.toList());\n                break;\n            default: // offline = saved metadata, not a video file\n                filtered = allItems.stream().filter(i -> !("completed".equals(i.status) && i.localPath != null && new File(i.localPath).exists()) && !"downloading".equals(i.status)).collect(Collectors.toList());\n                break;\n        }\n        b.emptyText.setVisibility(filtered.isEmpty() ? View.VISIBLE : View.GONE);\n        switch (currentTab) {\n            case "downloading": b.emptyText.setText("No active downloads."); break;\n            case "downloaded":  b.emptyText.setText("No downloaded videos yet.\\nUse the download button on any video."); break;\n            default:            b.emptyText.setText("Nothing saved offline yet."); break;\n        }\n        b.downloadsRv.setLayoutManager(new LinearLayoutManager(getContext()));\n        b.downloadsRv.setAdapter(new Adapter(filtered));\n    }\n    class Adapter extends RecyclerView.Adapter<Adapter.VH> {\n        List<DownloadItem> items;\n        Adapter(List<DownloadItem> i) { items = i; }\n        @NonNull @Override public VH onCreateViewHolder(@NonNull ViewGroup p, int t) {\n            LinearLayout row = new LinearLayout(p.getContext());\n            row.setOrientation(LinearLayout.HORIZONTAL);\n            row.setPadding(32, 24, 32, 24);\n            row.setBackgroundColor(0xFF141414);\n            TextView icon = new TextView(p.getContext());\n            icon.setTextSize(20); icon.setPadding(0, 0, 16, 0);\n            TextView tv = new TextView(p.getContext());\n            tv.setTextColor(0xFFFFFFFF); tv.setTextSize(14);\n            tv.setLayoutParams(new LinearLayout.LayoutParams(0, LinearLayout.LayoutParams.WRAP_CONTENT, 1f));\n            TextView del = new TextView(p.getContext());\n            del.setText("\\u2715"); del.setTextColor(0xFFCF6679); del.setTextSize(16); del.setPadding(16, 0, 0, 0);\n            row.addView(icon); row.addView(tv); row.addView(del);\n            return new VH(row, icon, tv, del);\n        }\n        @Override public void onBindViewHolder(@NonNull VH h, int pos) {\n            DownloadItem item = items.get(pos);\n            String label = item.title + (item.season > 0 ? "  S" + item.season + "E" + item.episode : "");\n            boolean playable = item.localPath != null && new File(item.localPath).exists();\n            h.icon.setText(playable ? "\\u25b6" : (item.status != null && item.status.equals("downloading") ? "\\u23ec" : "\\ud83d\\udce5"));\n            h.tv.setText(label);\n            h.tv.setTextColor(playable ? 0xFFFFFFFF : 0xFFAAAAAA);\n            h.tv.setOnClickListener(v -> {\n                if (playable) {\n                    try {\n                        Intent intent = new Intent(Intent.ACTION_VIEW);\n                        intent.setDataAndType(Uri.parse("file://" + item.localPath), "video/*");\n                        intent.addFlags(Intent.FLAG_GRANT_READ_URI_PERMISSION);\n                        startActivity(intent);\n                    } catch (Exception e) { Toast.makeText(getContext(), "No video player found", Toast.LENGTH_SHORT).show(); }\n                } else {\n                    Intent i = new Intent(getContext(), WatchActivity.class);\n                    i.putExtra("type", item.type); i.putExtra("id", item.tmdbId); startActivity(i);\n                }\n            });\n            h.del.setOnClickListener(v -> {\n                DownloadManager2.deleteDownload(requireContext(), item);\n                Toast.makeText(getContext(), "Deleted", Toast.LENGTH_SHORT).show();\n            });\n        }\n        @Override public int getItemCount() { return items.size(); }\n        class VH extends RecyclerView.ViewHolder { TextView icon, tv, del; VH(View r, TextView i, TextView t, TextView d) { super(r); icon=i; tv=t; del=d; } }\n    }\n    @Override public void onDestroyView() { super.onDestroyView(); b = null; }\n}\n')

